func _process_vs_incoming(delta: float) -> void:
	if not vs_match_gate_enabled or not vs_match_started or opening_build_active or run_finished:
		return
	if vs_active_payload.is_empty():
		if vs_incoming_queue.is_empty():
			return
		vs_active_payload = vs_incoming_queue.pop_front()
		vs_incoming_warning_timer = VS_SEND_BASE_WARNING + float(radar_cells.size()) * VS_SEND_RADAR_WARNING
		var sender := str(vs_active_payload.get("sender", "OPPONENT"))
		var label := str(vs_active_payload.get("label", "ENEMY SEND"))
		_show_alert("INCOMING FROM %s\n%s IN %.1fs" % [sender, label, vs_incoming_warning_timer], 2.2)
		_play_sound("play_error")
		command_message = "%s sent %s. Radar extends the warning before the enemy portal opens." % [sender, label]
		_update_interface()
		return
	vs_incoming_warning_timer = maxf(vs_incoming_warning_timer - delta, 0.0)
	if vs_incoming_warning_timer > 0.0:
		return
	_spawn_vs_payload(vs_active_payload)
	vs_active_payload = {}
	_update_interface()

